{
  "title": "ग्लोबल सेकेंडरी इंडेक्स",
  "group": "डायनामोडीबी इंडेक्स",
  "options": [
    {
      "text": "मुख्य कुंजी के समान होता है"
    },
    {
      "text": "अतिरिक्त लागत के बिना"
    },
    {
      "text": "लिखने के प्रदर्शन को कम करता है"
    },
    {
      "text": "गैर-मुख्य गुणों पर प्रश्न पूछने की अनुमति देता है"
    }
  ],
  "questionProse": [
    "डायनामोडीबी में ग्लोबल सेकेंडरी इंडेक्स का उद्देश्य क्या है?"
  ],
  "explanationProse": [
    "ग्लोबल सेकेंडरी इंडेक्स (GSI):\n    - गैर-मुख्य कुंजी गुणों पर प्रश्न पूछने की अनुमति देता है\n    - वैकल्पिक एक्सेस पैटर्न बनाता है\n    - प्रश्न की अधिकता को बढ़ाता है\n    - अतिरिक्त लिखने की क्षमता लागत के साथ आता है\n\n    मुख्य कुंजी से आगे जटिल प्रश्न आवश्यकताओं के लिए उपयोगी है।\n\n    [DynamoDB Indexes](https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/GSI.html)"
  ]
}
